sinu.taylor = Vectorize(function(x, s=1,k=1,order=14) {
  a = 2^(-1/s)
  sum = 0
  if ((x>0) & (x<1)) {
    for (n in 0:order) {
      sum = sum + (x-a)^n/factorial(n) * g.d(n,s,k)
    }
  }
  return (sum)
}, vectorize.args='x')

integrate(g.taylor, s=2,k=2, lower=0, upper=1)
integrate(sinu, s=2, k=2)

sinu = Vectorize(function(x, s=1,k=1) {
  if ((x>0) & (x<1)) {
    g = sin(pi * x^s)^k
  } else g = 0
  return (g)
}, vectorize.args='x')

curve(sinu(x, s=2, k=2), xlim=c(-1,2), ylim=c(-1,1))
curve(sinu.taylor(x, s=2, k=2, order=14), add=T, col='red')

g.area = function(s, k, order=14) {
  a = 2^(-1/s)
  sum = g(0,s,k)
  for (n in 1:order) {
    a_term = (1-a)^(n+1) - (-a)^(n+1)
    term = g.d(n,s,k) * a_term / factorial(n+1)
    sum = term + sum
  }
  return(sum)
}

g.rmom = function(r, s, k, order=14) {
  a = 2^(-1/s)
  sum = 0
  for (n in 0:order) {
    g.n = g.d(n, s, k)
    m = 0:r
    terms = choose(r, m) * (-a)^m / (r-m+n+1)
    innersum = sum(terms) * g.n / factorial(n)
    sum = innersum + sum
  }
  return(sum)
}

r = 1
g.rmom(r, 2, 2)/g.rmom(0, 2,2)

g.area(2,2)
sinu.area(2,2)

sinu.rmom(r, omega=2, chi=2)

sinu.area(2,2)
g.rmom(0,2,2)

sinu.rmom.taylor(1,2,2)


